local pending = 0
for id, def in pairs(partDefs) do
    pending = pending + 1
    task.spawn(function()
        local success, part = pcall(function()
            return endpoint:InvokeServer("CreatePart", def.shape, def.cframe, workspace)
        end)
        if success and part then
            P[id] = part
            syncAnchor(endpoint, part, true)
        end
        pending = pending - 1
    end)
end
while pending > 0 do
    task.wait()
end

